import{_ as s,C as r,o as t,c as n,a2 as d,b as i,w as o,a as c,E as l,a3 as p}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"ROS2 与 DDS 互操作深度解析","description":"","frontmatter":{},"headers":[],"relativePath":"2 计算机/中间件/DDS/ROS2与DDS互操作深度解析.md","filePath":"2 计算机/中间件/DDS/ROS2与DDS互操作深度解析.md","lastUpdated":1781599722000}'),D={name:"2 计算机/中间件/DDS/ROS2与DDS互操作深度解析.md"};function u(h,e,_,S,g,b){const a=r("Mermaid");return t(),n("div",null,[e[2]||(e[2]=d('<h1 id="ros2-与-dds-互操作深度解析" tabindex="-1">ROS2 与 DDS 互操作深度解析 <a class="header-anchor" href="#ros2-与-dds-互操作深度解析" aria-label="Permalink to &quot;ROS2 与 DDS 互操作深度解析&quot;">​</a></h1> <h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2> <p>ROS2 的通信后端是 DDS，但&quot;用了 DDS&quot;不等于&quot;DDS 之间天然互通&quot;。要让一个非 ROS2 的 DDS 节点（如 dds-wrapper）与 ROS2 互通，必须在 wire 层逐项对齐 ROS2 的约定。本文记录这些约定的原理、跨 DDS 互通的根本限制，以及 QoS 容错机制。</p> <h2 id="ros2-的序列化架构-dds-只是管道" tabindex="-1">ROS2 的序列化架构：DDS 只是管道 <a class="header-anchor" href="#ros2-的序列化架构-dds-只是管道" aria-label="Permalink to &quot;ROS2 的序列化架构：DDS 只是管道&quot;">​</a></h2> <p>关键认知：<strong>ROS2 没有用 DDS 自带的序列化</strong>。序列化发生在 typesupport 层，由 rosidl 工具链生成，DDS 被降级为&quot;透明传输管道&quot;，只搬 CDR 字节流，不参与编解码。</p> ',10)),(t(),i(p,null,{default:o(()=>[l(a,{id:"mermaid-15",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%22.msg%2F.srv%2F.action%22%5D%20--%3E%7Crosidl%20%E5%B7%A5%E5%85%B7%E9%93%BE%7C%20B%5B%22typesupport%20%E4%BB%A3%E7%A0%81%3Cbr%2F%3ECDR%20%E5%BA%8F%E5%88%97%E5%8C%96%E5%87%BD%E6%95%B0%22%5D%0A%20%20%20%20A%20--%3E%7Crosidl%20%E5%B7%A5%E5%85%B7%E9%93%BE%7C%20C%5B%22DDS%20IDL%20*_%20.idl%22%5D%0A%20%20%20%20B%20--%3E%20D%5B%22CDR%20%E5%AD%97%E8%8A%82%E6%B5%81%22%5D%0A%20%20%20%20C%20--%3E%20E%5B%22DDS%20%E7%B1%BB%E5%9E%8B%E6%B3%A8%E5%86%8C%22%5D%0A%20%20%20%20D%20--%3E%20F%5B%22DDS%20impl%EF%BC%88%E4%BC%A0%E8%BE%93%E7%AE%A1%E9%81%93%EF%BC%89%22%5D%0A%20%20%20%20E%20--%3E%20F%0A%20%20%20%20F%20--%3E%20G%5B%22%E7%BD%91%E7%BB%9C%22%5D%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[c(`
          Loading...
        `,-1)])]),_:1})),e[3]||(e[3]=d(`<p>每种 DDS 后端对应一个 typesupport 包：</p> <table tabindex="0"><thead><tr><th>DDS 后端</th> <th>typesupport 包</th> <th>序列化方式</th></tr></thead> <tbody><tr><td>FastDDS</td> <td><code>rosidl_typesupport_fastrtps_cpp</code></td> <td>生成直接调 Fast-CDR 的代码</td></tr> <tr><td>CycloneDDS</td> <td><code>rosidl_typesupport_introspection_cpp</code></td> <td>生成字段元数据，运行时遍历做通用 CDR 编解码</td></tr> <tr><td>Connext</td> <td><code>rosidl_typesupport_connext_cpp</code></td> <td>生成调 Connext CDR 的代码</td></tr></tbody></table> <p>ROS2 的不同 rmw_impl 之间能互通，是因为 typesupport 层统一了 wire 约定（type name 映射、CDR 编码细节、消息头格式）。<strong>绕过 typesupport 直接用 DDS 原生 API 的节点，只能与同一家 DDS（且 wire 约定一致）互通。</strong></p> <h2 id="wire-层命名规则" tabindex="-1">wire 层命名规则 <a class="header-anchor" href="#wire-层命名规则" aria-label="Permalink to &quot;wire 层命名规则&quot;">​</a></h2> <p>与 ROS2 互通，wire 层必须遵守 <code>rmw_cyclonedds_cpp</code> 的约定，分两部分：topic 前缀和类型名。</p> <h3 id="topic-命名前缀" tabindex="-1">Topic 命名前缀 <a class="header-anchor" href="#topic-命名前缀" aria-label="Permalink to &quot;Topic 命名前缀&quot;">​</a></h3> <table tabindex="0"><thead><tr><th>通信模式</th> <th>前缀</th> <th>示例</th></tr></thead> <tbody><tr><td>Topic</td> <td><code>rt/</code></td> <td><code>rt/fibonacci/_action/feedback</code></td></tr> <tr><td>Service request</td> <td><code>rq/</code></td> <td><code>rq/fibonacci/_action/send_goalRequest</code></td></tr> <tr><td>Service response</td> <td><code>rr/</code></td> <td><code>rr/fibonacci/_action/send_goalReply</code></td></tr></tbody></table> <p><code>enableRos2Compat(true)</code> 启用这些前缀。注意前缀无尾斜杠，拼接为 <code>make_fqtopic(&quot;rq&quot;, &quot;/fibonacci/...send_goal&quot;, &quot;Request&quot;)</code>。</p> <h3 id="类型名变换-rosidl-dds-规则" tabindex="-1">类型名变换（rosidl_dds 规则） <a class="header-anchor" href="#类型名变换-rosidl-dds-规则" aria-label="Permalink to &quot;类型名变换（rosidl_dds 规则）&quot;">​</a></h3> <p><code>rosidl_generator_dds_idl</code> 消费解析后的 IDL（不是原始 <code>.msg</code>），输出带尾下划线的 <code>{MessageName}_.idl</code>。三个结构性变换：</p> <ol><li><strong><code>module dds_</code> 包装</strong>：struct 嵌套在额外 <code>module dds_ { }</code> 中</li> <li><strong>struct 名尾下划线</strong>：<code>Test</code> → <code>Test_</code></li> <li><strong>成员名尾下划线</strong>：<code>bool_value</code> → <code>bool_value_</code></li></ol> <div class="language-idl vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">idl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module test_msgs {</span></span>
<span class="line"><span>module msg {</span></span>
<span class="line"><span>module dds_ {</span></span>
<span class="line"><span>struct Test_ {</span></span>
<span class="line"><span>    boolean bool_value_;</span></span>
<span class="line"><span>    octet   byte_value_;</span></span>
<span class="line"><span>    long    int32_value_;</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span>};</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>类型名公式：<code>::&#39;.join(namespaces + [&#39;dds_&#39;, name + &#39;_&#39;])</code>。例如 <code>std_msgs/msg/Header</code> → <code>std_msgs::msg::dds_::Header_</code>。</p> <h3 id="基本类型映射" tabindex="-1">基本类型映射 <a class="header-anchor" href="#基本类型映射" aria-label="Permalink to &quot;基本类型映射&quot;">​</a></h3> <table tabindex="0"><thead><tr><th>ROS 类型</th> <th>DDS IDL</th> <th>备注</th></tr></thead> <tbody><tr><td><code>int8</code> / <code>uint8</code></td> <td><code>octet</code></td> <td>DDS 无 signed byte，<strong>符号信息在 IDL 层丢失</strong></td></tr> <tr><td><code>int16</code> / <code>uint16</code></td> <td><code>short</code> / <code>unsigned short</code></td> <td></td></tr> <tr><td><code>int32</code> / <code>uint32</code></td> <td><code>long</code> / <code>unsigned long</code></td> <td></td></tr> <tr><td><code>int64</code> / <code>uint64</code></td> <td><code>long long</code> / <code>unsigned long long</code></td> <td></td></tr> <tr><td><code>string&lt;=N</code></td> <td><code>string&lt;N&gt;</code></td> <td>有界字符串</td></tr> <tr><td>固定数组</td> <td><code>&lt;type&gt; &lt;name&gt;_[&lt;size&gt;]</code></td> <td></td></tr> <tr><td>有界序列</td> <td><code>sequence&lt;&lt;type&gt;, &lt;max&gt;&gt; &lt;name&gt;_</code></td> <td></td></tr></tbody></table> <p>接口分解：Message 1:1 一个 struct；Service 1:2（request + response）；<strong>Action 1:7+</strong>（goal + result + feedback + feedback_message + send_goal req/resp + get_result req/resp）。</p> <h2 id="跨-dds-互通的根本限制" tabindex="-1">跨 DDS 互通的根本限制 <a class="header-anchor" href="#跨-dds-互通的根本限制" aria-label="Permalink to &quot;跨 DDS 互通的根本限制&quot;">​</a></h2> <p>DDS 实现之间理论上可互通（都遵循 CDR/RTPS 标准），但前提是<strong>双方对 wire 层的所有约定完全一致</strong>。实际障碍有三：</p> <ol><li><strong>type name</strong>：端点发现时用于匹配，不同 DDS 实现从同一份 IDL 生成的 type name 可能不同</li> <li><strong>CDR 封装细节</strong>：string、sequence 等的对齐和编码</li> <li><strong>TypeInformation 编码</strong>：CycloneDDS 用 XCDR2（符合 DDS-XTypes 1.3 §7.3.4.5），老版本 FastDDS 用 CDR1，解析方按错误格式读 → 崩溃（详见踩坑篇的 bad_alloc）</li></ol> <table tabindex="0"><thead><tr><th>互通场景</th> <th>是否可行</th></tr></thead> <tbody><tr><td>dds-wrapper ↔ dds-wrapper（同一 DDS 后端）</td> <td>是</td></tr> <tr><td>dds-wrapper ↔ ROS2 <code>rmw_cyclonedds_cpp</code></td> <td>是</td></tr> <tr><td>dds-wrapper ↔ ROS2 <code>rmw_fastrtps_cpp</code></td> <td>否（TypeInformation 编码冲突 + typesupport 约定不同）</td></tr> <tr><td>dds-wrapper ↔ 其他 DDS 原生节点</td> <td>取决于 wire 约定是否逐项一致</td></tr></tbody></table> <blockquote><p>这正是架构上选单供应商（CycloneDDS）的根本原因：多供应商互通需要自建 typesupport 统一层，成本远高于收益。</p></blockquote> <h2 id="service-头部注入-header-guid-header-seq" tabindex="-1">Service 头部注入（header_guid / header_seq） <a class="header-anchor" href="#service-头部注入-header-guid-header-seq" aria-label="Permalink to &quot;Service 头部注入（header_guid / header_seq）&quot;">​</a></h2> <p>ROS2 Service 的 wire 帧在 CDR payload 前有一段 header，由 <code>rmw_cyclonedds</code> 的序列化器 <code>put_bytes</code> 直接写入，<strong>不做对齐</strong>：</p> <div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[RTPS header 4B][guid 8B][seq 8B][IDL payload...]</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><code>guid</code> = DataWriter 的 <code>dds_instance_handle_t</code>（uint64_t）</li> <li><code>seq</code> = 全局递增的 int64_t</li> <li>IDL struct 本身<strong>不含</strong> header 字段，header 是序列化器额外 prepend 的</li></ul> <p>非 ROS2 的 DDS 实现要模拟这个 wire 格式，需要把 header 当作 IDL 的前两个字段（<code>header_guid</code> + <code>header_seq</code>），并保证 CDR 字节布局与 <code>put_bytes</code> 一致。注意 idlcxx 对 <code>uint64</code> 会插入 8 字节对齐 padding，若与 <code>put_bytes</code> 的无对齐行为错位会反序列化失败——实测在特定版本组合下 padding 影响被吸收，但这是脆弱点。</p> <h2 id="qos-与容错机制" tabindex="-1">QoS 与容错机制 <a class="header-anchor" href="#qos-与容错机制" aria-label="Permalink to &quot;QoS 与容错机制&quot;">​</a></h2> <h3 id="ros2-的三种容错-qos" tabindex="-1">ROS2 的三种容错 QoS <a class="header-anchor" href="#ros2-的三种容错-qos" aria-label="Permalink to &quot;ROS2 的三种容错 QoS&quot;">​</a></h3> <table tabindex="0"><thead><tr><th>QoS</th> <th>作用</th> <th>触发</th> <th>适用模式</th></tr></thead> <tbody><tr><td>Deadline</td> <td>超时检测</td> <td>期望时间内没收到新数据</td> <td>Topic</td></tr> <tr><td>Liveliness</td> <td>存活检测</td> <td>活跃性断言未在 lease 期内刷新</td> <td>Topic</td></tr> <tr><td>Lifespan</td> <td>数据过期</td> <td>数据存活超过设定时长被丢弃</td> <td>Topic</td></tr></tbody></table> <blockquote><p><strong>关键限制</strong>：Service 和 Action 在 ROS2 中<strong>没有原生的 Deadline/Liveliness 支持</strong>（Service deadline 仍是 ROS2 的 Future Work）。ROS2 Service 无法原生检测客户端断连（rclcpp#2241），server 永远不知道 client 死了。</p></blockquote> <p>补偿模式：用 <strong>心跳 Topic + Deadline QoS</strong> 检测对端存活。CycloneDDS 提供 WaitSet + StatusCondition + Listener 监听 QoS 违规（无需轮询）。</p> <h3 id="qos-兼容性是静默失败陷阱" tabindex="-1">QoS 兼容性是静默失败陷阱 <a class="header-anchor" href="#qos-兼容性是静默失败陷阱" aria-label="Permalink to &quot;QoS 兼容性是静默失败陷阱&quot;">​</a></h3> <p>DDS 匹配时，<strong>reader 要求的可靠性不能高于 writer 提供的</strong>。例如 RELIABLE reader 订阅 BEST_EFFORT writer → QoS 不兼容 → DDS <strong>静默拒绝匹配</strong>，不会报错，只是 matched 计数为 0。这类问题极难排查，表现为&quot;端点都在但收不到数据 / wait_for_server 超时&quot;。Action 各通道的 QoS 必须逐项与 ROS2 对齐（feedback 是 RELIABLE 不是 BEST_EFFORT，status 是 TRANSIENT_LOCAL + depth=1），否则触发静默失配（详见踩坑篇）。</p> <h2 id="要点" tabindex="-1">要点 <a class="header-anchor" href="#要点" aria-label="Permalink to &quot;要点&quot;">​</a></h2> <ul><li><strong>ROS2 的序列化在 typesupport 层，DDS 只是管道</strong>。绕过 typesupport 的原生 DDS 节点只能与同 vendor 互通。</li> <li><strong>wire 命名三件事</strong>：topic 前缀（<code>rt/</code>/<code>rq/</code>/<code>rr/</code>）、类型名（<code>dds_::Name_</code>）、成员名尾下划线。ROS2 rosidl 生成的 IDL 成员名带尾下划线（<code>goal_id_</code>），CycloneDDS XTypes 可能检查 member name。</li> <li><strong>跨 DDS 互通的前提是 wire 约定逐项一致</strong>：type name、CDR 编码、TypeInformation 编码。TypeInformation 的 XCDR2 vs CDR1 是 CycloneDDS 与老版 FastDDS 的死结。</li> <li><strong>int8/uint8 都映射 octet</strong>，符号信息在 IDL 层丢失。</li> <li><strong>Service wire 帧的 header（guid + seq）由序列化器 prepend，非对齐写入</strong>，模拟时要注意 idlcxx 的对齐 padding。</li> <li><strong>QoS 不兼容是静默失败</strong>：RELIABLE reader + BEST_EFFORT writer 会被 DDS 静默拒绝，永远收不到数据。</li> <li><strong>Service/Action 无原生 Deadline/Liveliness</strong>，靠心跳 Topic 补偿。</li></ul>`,67))])}const R=s(D,[["render",u]]);export{q as __pageData,R as default};
